#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

__kernel void lud_diagonal(__global float *m,
                           __local float *shadow,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        shadow[i * BLOCK_SIZE + tx] = m[(offset + i) * matrix_dim + offset + tx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        if (tx >= i) {
            float sum = shadow[i * BLOCK_SIZE + tx];
            for (int j = 0; j < i; j++) {
                sum -= shadow[i * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
            shadow[i * BLOCK_SIZE + tx] = sum;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (tx > i) {
            float sum = shadow[tx * BLOCK_SIZE + i];
            for (int j = 0; j < i; j++) {
                sum -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] = sum / shadow[i * BLOCK_SIZE + i];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int i = 0; i < BLOCK_SIZE; i++) {
        m[(offset + i) * matrix_dim + offset + tx] = shadow[i * BLOCK_SIZE + tx];
    }
}

__kernel void lud_perimeter(__global float *m,
                            __local float *dia,
                            __local float *peri_row,
                            __local float *peri_col,
                            int matrix_dim,
                            int offset)
{
    int tx = (int)get_local_id(0);
    int bx = (int)get_group_id(0);
    int chunk = bx + 1;

    if (tx < BLOCK_SIZE) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            dia[i * BLOCK_SIZE + tx] = m[(offset + i) * matrix_dim + offset + tx];
            peri_row[i * BLOCK_SIZE + tx] =
                m[(offset + i) * matrix_dim + (offset + chunk * BLOCK_SIZE + tx)];
        }
    } else {
        int r = tx - BLOCK_SIZE;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            peri_col[r * BLOCK_SIZE + j] =
                m[(offset + chunk * BLOCK_SIZE + r) * matrix_dim + (offset + j)];
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            float sum = peri_row[i * BLOCK_SIZE + tx];
            for (int k = 0; k < i; k++) {
                sum -= dia[i * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
            }
            peri_row[i * BLOCK_SIZE + tx] = sum;
        }

        for (int i = 0; i < BLOCK_SIZE; i++) {
            m[(offset + i) * matrix_dim + (offset + chunk * BLOCK_SIZE + tx)] =
                peri_row[i * BLOCK_SIZE + tx];
        }
    } else {
        int r = tx - BLOCK_SIZE;

        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = peri_col[r * BLOCK_SIZE + j];
            for (int k = 0; k < j; k++) {
                sum -= peri_col[r * BLOCK_SIZE + k] * dia[k * BLOCK_SIZE + j];
            }
            peri_col[r * BLOCK_SIZE + j] = sum / dia[j * BLOCK_SIZE + j];
        }

        for (int j = 0; j < BLOCK_SIZE; j++) {
            m[(offset + chunk * BLOCK_SIZE + r) * matrix_dim + (offset + j)] =
                peri_col[r * BLOCK_SIZE + j];
        }
    }
}

__kernel void lud_internal(__global float *m,
                           __local float *peri_row,
                           __local float *peri_col,
                           int matrix_dim,
                           int offset)
{
    int tx = (int)get_local_id(0);
    int ty = (int)get_local_id(1);
    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);

    int global_col = offset + (bx + 1) * BLOCK_SIZE + tx;
    int global_row = offset + (by + 1) * BLOCK_SIZE + ty;

    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col];
    peri_col[ty * BLOCK_SIZE + tx] = m[global_row * matrix_dim + (offset + tx)];
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += peri_col[ty * BLOCK_SIZE + k] * peri_row[k * BLOCK_SIZE + tx];
    }

    m[global_row * matrix_dim + global_col] -= sum;
}
